import React, { useState } from "react";
import MetricsChart from "./MetricsChart";
import ConfidenceMeter from "./ConfidenceMeter";
import DocumentCard from "./DocumentCard";

function Message({ msg }) {

  const [showOptions, setShowOptions] = useState(false);

  if (msg.type === "user") {
    return <div className="user-msg">{msg.text}</div>;
  }

  if (msg.loading) {
    return (
      <div className="ai-msg">
        <div className="pipeline-live">
          <span className="active">Query</span>
          <span>→</span>
          <span>Router</span>
          <span>→</span>
          <span>Retriever</span>
          <span>→</span>
          <span>Reasoning</span>
          <span>→</span>
          <span>Formatter</span>
        </div>
        <div className="thinking">Processing agents...</div>
      </div>
    );
  }

  const answerSteps = msg.answer?.split("•").filter(p => p.trim());

  const copyFull = () => {
    navigator.clipboard.writeText(msg.answer);
    setShowOptions(false);
  };

  const copyAnswerOnly = () => {
    navigator.clipboard.writeText(answerSteps.join("\n"));
    setShowOptions(false);
  };

  return (
    <div className="ai-msg">

      {/* ANSWER AS STEPS */}
      <div className="section-card">
        <h4>Final Answer</h4>
        {answerSteps.map((step, i) => (
          <div key={i} className="step-card">
            {step}
          </div>
        ))}
      </div>

      {/* DOCUMENTS */}
      <div className="section-card">
        <h4>Top Documents</h4>
        {msg.explanations?.map((doc, i) => (
          <DocumentCard key={i} doc={doc} />
        ))}
      </div>

      {/* METRICS */}
      <div className="section-card">
        <h4>RAG Metrics</h4>

        <ConfidenceMeter level={msg.metrics?.["Confidence Level"]} />

        <div style={{ width: "200px", margin: "auto" }}>
          <MetricsChart metrics={msg.metrics} />
        </div>
      </div>

      {/* COPY */}
      <div className="copy-container bottom-copy">
        <button className="copy-btn" onClick={() => setShowOptions(!showOptions)}>
          📋
        </button>

        {showOptions && (
          <div className="copy-dropdown">
            <div onClick={copyFull}>Copy full</div>
            <div onClick={copyAnswerOnly}>Copy answer</div>
          </div>
        )}
      </div>

    </div>
  );
}

export default Message;
